export function parseArgs(argv) {
  const result = { _: [] }
  let i = 0
  while (i < argv.length) {
    const arg = argv[i]
    if (!arg.startsWith('-')) {
      result._.push(arg)
      i += 1
      continue
    }
    if (arg.includes('=')) {
      const key = arg.slice(2)
      const value = arg.slice(key.length + 2)
      result[key] = value
      i += 1
      continue
    }
    if (i + 1 < argv.length) {
      const next = argv[i + 1]
      if (!next.startsWith('-')) {
        result[arg.slice(2)] = next
        i += 2
        continue
      }
    }
    result[arg.slice(2)] = true
    i += 1
  }
  return result
}

